    baladi: `יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵיהּ רַבָּא. (אמן) דַּעֲתִיד לְחַדָּתָא עָלְמָא וּלְאַחָאָה מִיתַיָּא. וּלְמִפְרַק חַיַיָּא. וּלְמִבְנֵי קַרְתָּא יְרוּשְׁלַם. וּלְשַׁכְלָלָא הֵיכְלָא קַדִּישָׁא. וּלְמִעְקַר פּוּלְחָנָא נוּכְרָאָה מִן אַרְעָא. וּלְאָתָבָא פוּלְחָנָא דִּי שְׁמֵיהּ לְאַתְרֵיהּ. בְּהַדְרֵיהּ בְּזִיוֵיהּ וּבִיקָרֵיהּ. וְיִמְלוֹךְ מַלְכוּתֵיהּ וְיַצְמַח פּוּרְקָנֵיהּ וִיקָרֵב מְשִׁיחֵיהּ וְיִפְרוֹק עַמֵּיהּ. בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּיהוֹן דְּכָל בֵּית יִשְׂרָאֵל, בַּעֲגַלָא וּבִזְמָן קָרִיב וְאִמְרוּ אָמֵן. (אמן) יְהֶא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: יִתְבָּרַךְ. (אמן). וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְעַלֶּה וְיִתְהַדַּר וְיִתְהַלַּל וְיִתְנַשֵּׂא, שְׁמֵיהּ דְּקֻדְשָׁא בְּרִיךְ הוּא. (אמן) לְעֵילָא לְעֵילָא מִכָּל בִּרְכָתָא שִׁירָתָא וְתֻשְׁבְּחָתָא וְנֶחָמָתָא, דַּאֲמִירָן בְּעָלְמָא וְאִמְרוּ אָמֵן. (אמן) עַל יִשְׂרָאֵל, וְעַל רַבָּנַן, וְעַל תַּלְמִידֵיהוֹן, וְעַל כָּל תַּלְמִידֵי תַּלְמִידֵיהוֹן, דְּעָסְקִין בְּאוֹרָיְתָא דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לְהוֹן וְלַנָא חִנָּא וְחִסְדָּא וְרַחֲמֵי מִן קֳדָם אֲבוּנָא דְּבִשְׁמַיָּא וְאִמְרוּ אָמֵן. (אמן) יְהֶא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, וְסִיַּעְתָּא וּפוּרְקָנָא וּרְוַחָא וְחִנָּא וְחִסְדָּא וְרַחֲמֵי עֲלֵיכוֹן וַעֲלַנָא וְעַל כָּל קְהָלְהוֹן דְּכָל בֵּית יִשְׂרָאֵל לְחַיִּים וּלְשָׁלוֹם וְאִמְרוּ אָמֵן. (אמן) עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו וַחֲסָדָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל. וִינַחֲמֵנוּ בְצִיּוֹן וְיִבְנֶה בְרַחֲמָיו אֶת יְרוּשָׁלָיִם בְּחַיֵּינוּ וּבְיָמֵינוּ בְּקָרוֹב אָמֵן וְאָמֵן:`,
    shami: ` יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵיהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא כִרְעוּתֵיהּ, וְיַמְלִיךְ מַלְכוּתֵיהּ, וְיַצְמַח פּוּרְקָנֵיהּ, וִיקָרֵב מְשִׁיחֵיהּ, וְיִפְרוֹק עַמֵּיהּ. בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּיהוֹן דְּכָל בֵּית יִשְׂרָאֵל, בַּעֲגַלָא וּבִזְמָן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן. יְהֶא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ:] יְהֶא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ.[אָמֵן] וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדַּר וְיִתְעַלֶּה וְיִתְהַלָּל, שְׁמֵיהּ דְּקוּדְשָׁא בְּרִיךְ הוּא. [אָמֵן] לְעֵילָא מִן כָּל [בעשי"ת אומר: לְעֵילָא לְעֵילָא מִכָּל] בִּרְכָתָא שִׁירָתָא תִּשְׁבְּחָתָא וְנֶחָמָתָא, דַּאֲמִירָן בְּעָלְמָא וְאִמְרוּ אָמֵן: עַל יִשְׂרָאֵל, וְעַל רַבָּנַן, וְעַל תַּלְמִידֵיהוֹן, וְעַל כָּל תַּלְמִידֵי תַּלְמִידֵיהוֹן, דְּיָתְבִין וְעָסְקִין בְּאוֹרָיְתָא קַדִּישְׁתָא, דִּי בְאַתְרָא הָדֵין, וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לְכוֹן, וּלְהוֹן, וְלַנָא, חִנָּא וְחִסְדָּא וְרַחֲמֵי, מִן קֳדָם אֲבוּנָא דְּבִשְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֶא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים, וְשָׂבָע, וִישׁוּעָה, וְנֶחָמָה, וְשֵׁיזָבָא, וּרְפוּאָה, וּגְאֻלָּה, וּמְחִילָה, וּסְלִיחָה, וְכַפָּרָה, וְרֶוַח, וְהַצָּלָה, וְהַצְלָחָה, וּפַרְנָסָה טוֹבָה לָנוּ וּלְכָל עַמּוֹ בֵית יִשְׂרָאֵל לְחַיִּים וּלְשָׁלוֹם וְאִמְרוּ אָמֵן: [אָמֵן] עֹשֶׂה שָׁלוֹם [בעשי"ת אומר: הַשָּׁלוֹם] בִּמְרוֹמָיו, הוּא בְרַחֲמָיו וַחֲסָדָיו, יַעֲשֶׂה שָׁלוֹם עָלֵינוּ, וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:`
